82	>
83	class CollectiveEpilogue<
84	    Sm90TmaWarpSpecialized<StagesC_,StagesD_,FragmentSize_,ReuseSmemC_,DelayTmaStore_>,
85	    CtaTileMNK_,
86	    EpilogueTile_,
87	    ElementC_,
88	    StrideC_,
89	    ElementD_,
90	    StrideD_,
91	    FusionCallbacks_,
92	    CopyOpG2S_,
93	    SmemLayoutAtomC_,
94	    CopyOpS2R_,
95	    CopyOpS2G_,
96	    SmemLayoutAtomD_,
97	    CopyOpR2S_,
98	    CopyAtomC_,
99	    CopyOpR2R_
100	> {
101	public:
102	  //
103	  // Type Aliases
104	  //
105	  using DispatchPolicy = Sm90TmaWarpSpecialized<StagesC_,StagesD_,FragmentSize_,ReuseSmemC_,DelayTmaStore_>;
106	  using CtaTileMNK = CtaTileMNK_;
107	  using EpilogueTile = EpilogueTile_;
108	  using FusionCallbacks = FusionCallbacks_;
109	  using ElementC = ElementC_;
110	  using StrideC = StrideC_;
111	  using ElementD = ElementD_;
112	  using StrideD = StrideD_;
113	  using CopyOpG2S = CopyOpG2S_;
114	  using SmemLayoutAtomC = SmemLayoutAtomC_;
115	  using CopyOpS2R = CopyOpS2R_;
116	  using CopyOpS2G = CopyOpS2G_;
117	  using SmemLayoutAtomD = SmemLayoutAtomD_;
118	  using CopyOpR2S = CopyOpR2S_;
119	  using CopyAtomC = CopyAtomC_;
120	  using CopyOpR2R = CopyOpR2R_;
121	
122	  using ThreadEpilogueOp = typename epilogue::fusion::FusionCallbacksTraits<FusionCallbacks>::Operation;
123	  using GmemTiledCopyC = CopyOpG2S;
124	  using GmemTiledCopyD = CopyOpS2G;
125	
126	  static_assert(!is_layout<EpilogueTile>::value && is_tuple<EpilogueTile>::value, "EpilogueTile must be a cute::Tile or cute::Shape");
127	  static_assert(cute::rank(CtaTileMNK{}) == 3, "CtaTileMNK must be rank-3: [CTA_M, CTA_N, CTA_K]");
128	  static_assert(cute::rank(EpilogueTile{}) == 2, "EpilogueTile must be rank-2: [EPI_TILE_M, EPI_TILE_N]");
129	  static_assert(size<0>(CtaTileMNK{}) % size<0>(shape(EpilogueTile{})) == 0, "EPI_TILE_M must divide CTA_M");
130	  static_assert(size<1>(CtaTileMNK{}) % size<1>(shape(EpilogueTile{})) == 0, "EPI_TILE_N must divide CTA_N");
131	  static_assert(cute::rank(StrideC{}) == 3, "StrideC must be rank-3: [M, N, L]");
132	  static_assert(cute::rank(StrideD{}) == 3, "StrideD must be rank-3: [M, N, L]");
133	
134	private:
135	  constexpr static bool is_source_supported = not cute::is_void_v<ElementC>;
136	  constexpr static bool is_destination_supported = not cute::is_void_v<ElementD>;
137	  using NonVoidElementD = cute::conditional_t<not is_destination_supported,fusion::get_element_aux_t<FusionCallbacks>, ElementD>;
138	  static_assert(not cute::is_void_v<NonVoidElementD>, "SmemElementD is void");
139	  using NonVoidElementC = cute::conditional_t<not is_source_supported,NonVoidElementD,ElementC>; // prevents void ref breakages
140	
141	  using TmaElementD = cute::conditional_t<cute::is_same_v<NonVoidElementD, cutlass::complex<float>>, uint64_t, NonVoidElementD>;
142	  using TmaElementC = cute::conditional_t<cute::is_same_v<NonVoidElementC, cutlass::complex<float>>, uint64_t, NonVoidElementC>;
143	
144	  using SmemElementC = typename cutlass::detail::get_unpacked_element_type<NonVoidElementC>::type;
145	  using SmemElementD = typename cutlass::detail::get_unpacked_element_type<NonVoidElementD>::type;
146	
147	  constexpr static int StagesC = StagesC_;
148	  constexpr static int StagesD = StagesD_;
149	  constexpr static bool ReuseSmemC = ReuseSmemC_ and is_destination_supported;
150	  constexpr static bool DelayTmaStore = DelayTmaStore_;
151	
152	  constexpr static bool is_m_major_C = detail::is_m_major<StrideC>();
153	  constexpr static bool is_m_major_D = detail::is_m_major<StrideD>();
154	
155	  constexpr static bool is_im2col_C = cute::is_same_v<CopyOpG2S, SM90_TMA_LOAD_IM2COL>;
