483	struct Sm90VisitorImplBase {
484	  // Shared memory allocation
485	  using SharedStorage = tuple<typename Ops::SharedStorage...>;
486	  // Host side fusion arguments
487	  using Arguments = tuple<typename Ops::Arguments...>;
488	  // Device side fusion params (Kernel-entry API)
489	  using Params = tuple<typename Ops::Params...>;
490	  // Tensormap argument type used in ptr-array epilogues. The pack expansion is
491	  // delegated to tensormaps_tuple_for above; spelling it inline here trips an
492	  // MSVC bug with alias-template pack expansion over an enclosing class's pack.
493	  template <bool IsLoad>
494	  using TensorMaps = typename tensormaps_tuple_for<IsLoad, Ops...>::type;
495	
496	  template <class ProblemShape>
497	  static constexpr Params
498	  to_underlying_arguments(ProblemShape const& problem_shape, Arguments const& args, void* workspace) {
499	    uint8_t* op_workspace = reinterpret_cast<uint8_t*>(workspace);
